func NewBrookLink(link string) (*BrookLink, error) {
	var address, host, path string
	kind, server, v, err := ParseLink(link)
	if err != nil {
		return nil, err
	}
	p := []byte(v.Get("password"))
	if kind == "server" {
		address = server
	}
	var tc *tls.Config
	var tlsfingerprint utls.ClientHelloID
	var fragmentMinLength int64
	var fragmentMaxLength int64
	var fragmentMinDelay int64
	var fragmentMaxDelay int64
	if kind == "socks5" || kind == "wsserver" || kind == "wssserver" || kind == "quicserver" {
		u, err := url.Parse(server)
		if err != nil {
			return nil, err
		}
		host = u.Host
		path = u.Path
		if path == "" {
			path = "/ws"
		}
		address = host
		if kind == "wsserver" || kind == "wssserver" || kind == "quicserver" {
			if v.Get("address") != "" {
				address = v.Get("address")
			}
		}
		if kind == "wssserver" || kind == "quicserver" {
			h, _, err := net.SplitHostPort(u.Host)
			if err != nil {
				return nil, err
			}
			tc = &tls.Config{ServerName: h}
			if v.Get("insecure") == "true" {
				tc.InsecureSkipVerify = true
			}
			if v.Get("ca") != "" {
				roots := x509.NewCertPool()
				ok := roots.AppendCertsFromPEM([]byte(v.Get("ca")))
				if !ok {
					return nil, errors.New("failed to parse root certificate")
				}
				tc.RootCAs = roots
			}
			if kind == "wssserver" {
				tc.NextProtos = []string{"http/1.1"}
			}
			if kind == "quicserver" {
				tc.NextProtos = []string{"h3"}
			}
		}
		if kind == "wsserver" || kind == "wssserver" || kind == "quicserver" {
			if v.Get("withoutBrookProtocol") == "true" {
				p, err = SHA256Bytes([]byte(v.Get("password")))
				if err != nil {
					return nil, err
				}
			}
		}
		if kind == "wssserver" {
			if v.Get("tlsfingerprint") == "chrome" {
				tlsfingerprint = utls.HelloChrome_Auto
			}
			if v.Get("fragment") != "" {
				l := strings.Split(v.Get("fragment"), ":")
				if len(l) == 4 {
					fragmentMinLength, _ = strconv.ParseInt(l[0], 10, 64)
					fragmentMaxLength, _ = strconv.ParseInt(l[1], 10, 64)
					fragmentMinDelay, _ = strconv.ParseInt(l[2], 10, 64)
					fragmentMaxDelay, _ = strconv.ParseInt(l[3], 10, 64)
				}
			}
		}
	}
	return &BrookLink{
		Kind:              kind,
		Address:           address,
		Host:              host,
		Path:              path,
		Password:          p,
		V:                 v,
		Tc:                tc,
		TLSFingerprint:    tlsfingerprint,
		FragmentMinLength: fragmentMinLength,
		FragmentMaxLength: fragmentMaxLength,
		FragmentMinDelay:  fragmentMinDelay,
		FragmentMaxDelay:  fragmentMaxDelay,
	}, nil
}

func WebSocketDial(src, dst, addr, host, path string, tc *tls.Config, timeout int, tlsfingerprint utls.ClientHelloID, fragmentMinLength, fragmentMaxLength, fragmentMinDelay, fragmentMaxDelay int64) (net.Conn, error) {
	var c net.Conn
	var err error
	if src == "" || dst == "" {
		c, err = DialTCP("tcp", "", addr)
	}
	if src != "" && dst != "" {
		c, err = NATDial("tcp", src, dst, addr)
	}
	if err != nil {
		return nil, err
	}
	if timeout != 0 {
		if err := c.SetDeadline(time.Now().Add(time.Duration(timeout) * time.Second)); err != nil {
			c.Close()
			return nil, err
		}
	}
	if tc != nil {
		if fragmentMinLength != 0 && fragmentMaxLength != 0 && fragmentMinDelay != 0 && fragmentMaxDelay != 0 {
			c = &TLSFragmentConn{
				Conn:      c,
				MinLength: fragmentMinLength,
				MaxLength: fragmentMaxLength,
				MinDelay:  fragmentMinDelay,
				MaxDelay:  fragmentMaxDelay,
			}
		}
		if tlsfingerprint.Client == "" {
			c1 := tls.Client(c, tc)
			if err := c1.Handshake(); err != nil {
				c1.Close()
				return nil, err
			}
			s := host
			h, _, err := net.SplitHostPort(host)
			if err == nil {
				s = h
			}
			if !tc.InsecureSkipVerify {
				if err := c1.VerifyHostname(s); err != nil {
					c1.Close()
					return nil, err
				}
			}
			c = c1
		}
		if tlsfingerprint.Client != "" {
			c1 := utls.UClient(c, &utls.Config{
				ServerName:         tc.ServerName,
				NextProtos:         tc.NextProtos,
				InsecureSkipVerify: tc.InsecureSkipVerify,
				RootCAs:            tc.RootCAs,
			}, tlsfingerprint)
			s := host
			h, _, err := net.SplitHostPort(host)
			if err == nil {
				s = h
			}
			if err := c1.BuildHandshakeState(); err != nil {
				return nil, err
			}
			for _, v := range c1.Extensions {
				if vv, ok := v.(*utls.ALPNExtension); ok {
					if tlsfingerprint.Client == "Chrome" {
						vv.AlpnProtocols = []string{"http/1.1"}
					}
					break
				}
			}
			if err := c1.BuildHandshakeState(); err != nil {
				return nil, err
			}
			if err := c1.Handshake(); err != nil {
				c1.Close()
				return nil, err
			}
			if !tc.InsecureSkipVerify {
				if err := c1.VerifyHostname(s); err != nil {
					c1.Close()
					return nil, err
				}
			}
			c = c1
		}
	}
	p := x1.BP16.Get().([]byte)
	if _, err := io.ReadFull(rand.Reader, p); err != nil {
		x1.BP16.Put(p)
		c.Close()
		return nil, err
	}
	k := base64.StdEncoding.EncodeToString(p)
	x1.BP16.Put(p)
	b := make([]byte, 0, 300)
	b = append(b, []byte("GET "+path+" HTTP/1.1\r\n")...)
	b = append(b, []byte(fmt.Sprintf("Host: %s\r\n", host))...)
	b = append(b, []byte("Upgrade: websocket\r\n")...)
	b = append(b, []byte("Connection: Upgrade\r\n")...)
	b = append(b, []byte(fmt.Sprintf("Sec-WebSocket-Key: %s\r\n", k))...)
	b = append(b, []byte("Sec-WebSocket-Version: 13\r\n\r\n")...)
	if _, err := c.Write(b); err != nil {
		c.Close()
		return nil, err
	}
	r := bufio.NewReader(c)
	for {
		b, err = r.ReadBytes('\n')
		if err != nil {
			c.Close()
			return nil, err
		}
		b = bytes.TrimSpace(b)
		if len(b) == 0 {
			break
		}
		if bytes.HasPrefix(b, []byte("HTTP/1.1 ")) {
			if !bytes.Contains(b, []byte("101")) {
				c.Close()
				return nil, errors.New(string(b))
			}
		}
		if bytes.HasPrefix(b, []byte("Sec-WebSocket-Accept: ")) {
			h := sha1.New()
			h.Write([]byte(k))
			h.Write([]byte("258EAFA5-E914-47DA-95CA-C5AB0DC85B11"))
			ak := base64.StdEncoding.EncodeToString(h.Sum(nil))
			if string(b[len("Sec-WebSocket-Accept: "):]) != ak {
				c.Close()
				return nil, errors.New(string(b))
			}
		}
	}
	return c, nil
}
